import{_ as e,o as l,c as n,a2 as a}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"F09: 毛利率、營業利益率與淨利率連動關係審計 - 財務分析專家 (finance-financial-analyst) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F09_毛利變動與經營槓桿審計_財務分析專家.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F09_毛利變動與經營槓桿審計_財務分析專家.md"}'),r={name:"審計報告庫/財務審計/6290_良維/20260424/F09_毛利變動與經營槓桿審計_財務分析專家.md"};function d(s,t,i,g,c,o){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="f09-毛利率、營業利益率與淨利率連動關係審計-財務分析專家-finance-financial-analyst-審計報告" tabindex="-1">F09: 毛利率、營業利益率與淨利率連動關係審計 - 財務分析專家 (finance-financial-analyst) 審計報告 <a class="header-anchor" href="#f09-毛利率、營業利益率與淨利率連動關係審計-財務分析專家-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F09: 毛利率、營業利益率與淨利率連動關係審計 - 財務分析專家 (finance-financial-analyst) 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>毛利率 (GM)、營業利益率 (OPM) 與淨利率的連動關係為何？是否存在經營槓桿 (Operating Leverage) 放大或侵蝕損益的現象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 2025 年 Q4（2025 年報已公告）之最新公開數據，<strong>良維 (6290) 正處於「結構性獲利升級」階段，經營槓桿強烈正向放大</strong>。2025 全年毛利率較 2024 年跳升 6.56 個百分點（24.86% → 31.42%），營業利益率同步擴張 5.98 個百分點（11.89% → 17.87%），三率同向攀升。2025 年營收年增 26.3%，營業利益年增高達 90.0%，經營槓桿倍數 (DOL) 達 3.41 倍，顯示規模經濟效益顯著。惟 2025 Q4 行銷費用急增（Selling/Rev 升至 14.88% vs 年度均值 ~11%），潛藏「季度行銷擴張」訊號，需關注費用率是否能隨營收規模持續優化。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良 — 獲利結構穩健，經營槓桿高效兌現中）</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">年度指標</th><th style="text-align:center;">2024 全年</th><th style="text-align:center;">2025 全年</th><th style="text-align:center;">變動 (bps)</th></tr></thead><tbody><tr><td style="text-align:left;">營收 (TWD)</td><td style="text-align:center;">8,040,447,000</td><td style="text-align:center;">10,158,601,000</td><td style="text-align:center;">+26.3%</td></tr><tr><td style="text-align:left;">毛利率 (GM)</td><td style="text-align:center;">24.86%</td><td style="text-align:center;">31.42%</td><td style="text-align:center;">+656</td></tr><tr><td style="text-align:left;">營業利益率 (OPM)</td><td style="text-align:center;">11.89%</td><td style="text-align:center;">17.87%</td><td style="text-align:center;">+598</td></tr><tr><td style="text-align:left;">淨利率 (NPM, 母公司)</td><td style="text-align:center;">12.57%</td><td style="text-align:center;">13.84%</td><td style="text-align:center;">+127</td></tr><tr><td style="text-align:left;">營業費用率 (OpExp/Rev)</td><td style="text-align:center;">14.26%</td><td style="text-align:center;">14.02%</td><td style="text-align:center;">-24</td></tr><tr><td style="text-align:left;">EPS (TWD)</td><td style="text-align:center;">6.41</td><td style="text-align:center;">8.31</td><td style="text-align:center;">+29.6%</td></tr><tr><td style="text-align:left;">DOL (經營槓桿倍數)</td><td style="text-align:center;">—</td><td style="text-align:center;">3.41x (Revenue +1% → OpInc +3.41%)</td><td style="text-align:center;">強正向</td></tr></tbody></table><p><strong>核心數據基石</strong>：2024 年三率為 24.86%/11.89%/12.57%，2025 年三率為 31.42%/17.87%/13.84%。毛利率與營益率同步大幅擴張，淨利率因 2025 Q2 業外大額匯兌損失 (-260.5M) 被壓縮，造成全年淨利率增幅僅 +127 bps，落後營益率 +598 bps 的變動幅度。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、逐季三率連動分析-2023-q2-2025-q4" tabindex="-1">一、逐季三率連動分析（2023 Q2 ~ 2025 Q4） <a class="header-anchor" href="#一、逐季三率連動分析-2023-q2-2025-q4" aria-label="Permalink to &quot;一、逐季三率連動分析（2023 Q2 ~ 2025 Q4）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">營收 (千元)</th><th style="text-align:center;">GM</th><th style="text-align:center;">OPM</th><th style="text-align:center;">NPM (母公司)</th><th style="text-align:center;">OpExp/Rev</th><th style="text-align:center;">EPS</th></tr></thead><tbody><tr><td style="text-align:left;">2023-Q2</td><td style="text-align:center;">1,786,810</td><td style="text-align:center;">18.88%</td><td style="text-align:center;">7.52%</td><td style="text-align:center;">6.55%</td><td style="text-align:center;">11.97%</td><td style="text-align:center;">0.76</td></tr><tr><td style="text-align:left;">2023-Q3</td><td style="text-align:center;">2,005,659</td><td style="text-align:center;">29.28%</td><td style="text-align:center;">16.45%</td><td style="text-align:center;">20.23%</td><td style="text-align:center;">13.10%</td><td style="text-align:center;">2.64</td></tr><tr><td style="text-align:left;">2023-Q4</td><td style="text-align:center;">1,975,717</td><td style="text-align:center;">31.57%</td><td style="text-align:center;">5.30%</td><td style="text-align:center;">2.08%</td><td style="text-align:center;"><strong>26.67%</strong></td><td style="text-align:center;">0.26</td></tr><tr><td style="text-align:left;">2024-Q1</td><td style="text-align:center;">1,740,928</td><td style="text-align:center;">27.55%</td><td style="text-align:center;">11.67%</td><td style="text-align:center;">15.18%</td><td style="text-align:center;">16.15%</td><td style="text-align:center;">1.70</td></tr><tr><td style="text-align:left;">2024-Q2</td><td style="text-align:center;">1,919,338</td><td style="text-align:center;">24.69%</td><td style="text-align:center;">15.24%</td><td style="text-align:center;">15.36%</td><td style="text-align:center;">13.06%</td><td style="text-align:center;">1.86</td></tr><tr><td style="text-align:left;">2024-Q3</td><td style="text-align:center;">2,151,150</td><td style="text-align:center;"><strong>19.98%</strong></td><td style="text-align:center;"><strong>7.21%</strong></td><td style="text-align:center;">5.52%</td><td style="text-align:center;">14.01%</td><td style="text-align:center;">0.75</td></tr><tr><td style="text-align:left;">2024-Q4</td><td style="text-align:center;">2,229,031</td><td style="text-align:center;">27.61%</td><td style="text-align:center;">13.68%</td><td style="text-align:center;">14.94%</td><td style="text-align:center;">14.05%</td><td style="text-align:center;">2.11</td></tr><tr><td style="text-align:left;">2025-Q1</td><td style="text-align:center;">2,341,020</td><td style="text-align:center;">29.45%</td><td style="text-align:center;"><strong>18.74%</strong></td><td style="text-align:center;">17.41%</td><td style="text-align:center;"><strong>11.06%</strong></td><td style="text-align:center;">2.56</td></tr><tr><td style="text-align:left;">2025-Q2</td><td style="text-align:center;">2,613,159</td><td style="text-align:center;">31.04%</td><td style="text-align:center;">20.55%</td><td style="text-align:center;"><strong>6.44%</strong></td><td style="text-align:center;">11.38%</td><td style="text-align:center;">1.06</td></tr><tr><td style="text-align:left;">2025-Q3</td><td style="text-align:center;">2,530,467</td><td style="text-align:center;">30.06%</td><td style="text-align:center;">15.95%</td><td style="text-align:center;">16.25%</td><td style="text-align:center;">14.40%</td><td style="text-align:center;">2.57</td></tr><tr><td style="text-align:left;">2025-Q4</td><td style="text-align:center;">2,673,955</td><td style="text-align:center;"><strong>34.79%</strong></td><td style="text-align:center;">16.32%</td><td style="text-align:center;">15.67%</td><td style="text-align:center;"><strong>18.83%</strong></td><td style="text-align:center;">2.53</td></tr></tbody></table><p><strong>關鍵發現</strong>：</p><ol><li><strong>GM 結構性攀升</strong>：從 2024 Q3 的低點 19.98% 逐季回升至 2025 Q4 的 34.79%，累計反彈 +1,481 bps。主因為資料中心 / AI 伺服器大電流電源線（佔營收比重從 5 年前不到 10% 升至 2025 年的 36%）的高毛利挹注。</li><li><strong>OPM 同步擴張</strong>：2025 Q1 達 18.74% 創近期高點，雖 Q2-Q4 回落至 15.95%-20.55% 區間，但全年均值 17.87% 較 2024 年 11.89% 增加 +598 bps，證明了「毛利擴張可有效轉化為營利增長」的良好傳導機制。</li><li><strong>NPM 受業外干擾</strong>：2025 Q2 因業外損失 -260.5M（推測為匯兌損失），淨利率驟降至 6.44%，EPS 僅 1.06。扣除該干擾，本業獲利穩健。</li></ol><h3 id="二、經營槓桿效率檢驗" tabindex="-1">二、經營槓桿效率檢驗 <a class="header-anchor" href="#二、經營槓桿效率檢驗" aria-label="Permalink to &quot;二、經營槓桿效率檢驗&quot;">​</a></h3><p><strong>2025 全年 DOL (Degree of Operating Leverage) 分析</strong>：</p><ul><li>營收 YoY: +26.3%</li><li>營業利益 YoY: <strong>+90.0%</strong></li><li>DOL = 90.0% / 26.3% = <strong>3.41x</strong></li><li>意即營收每成長 1%，營業利益可成長 3.41%，屬「高效能正向槓桿」</li></ul><p><strong>逐季 YoY 經營槓桿拐點</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">比較</th><th style="text-align:center;">Rev 成長</th><th style="text-align:center;">OpInc 成長</th><th style="text-align:center;">判定</th></tr></thead><tbody><tr><td style="text-align:left;">2024-Q2 vs 2023-Q2</td><td style="text-align:center;">+7.4%</td><td style="text-align:center;">+117.6%</td><td style="text-align:center;">正向放大（基期低）</td></tr><tr><td style="text-align:left;">2024-Q3 vs 2023-Q3</td><td style="text-align:center;">+7.3%</td><td style="text-align:center;"><strong>-53.0%</strong></td><td style="text-align:center;">負向放大（GM 驟降）</td></tr><tr><td style="text-align:left;">2024-Q4 vs 2023-Q4</td><td style="text-align:center;">+12.8%</td><td style="text-align:center;">+191.5%</td><td style="text-align:center;">正向放大（費用正常化）</td></tr><tr><td style="text-align:left;">2025-Q1 vs 2024-Q1</td><td style="text-align:center;">+34.5%</td><td style="text-align:center;">+115.9%</td><td style="text-align:center;">強正向（淡季不淡）</td></tr><tr><td style="text-align:left;">2025-Q2 vs 2024-Q2</td><td style="text-align:center;">+36.1%</td><td style="text-align:center;">+83.6%</td><td style="text-align:center;">正向（但業外吞噬淨利）</td></tr><tr><td style="text-align:left;">2025-Q3 vs 2024-Q3</td><td style="text-align:center;">+17.6%</td><td style="text-align:center;"><strong>+160.2%</strong></td><td style="text-align:center;">強正向（GM 大反彈）</td></tr><tr><td style="text-align:left;">2025-Q4 vs 2024-Q4</td><td style="text-align:center;">+20.0%</td><td style="text-align:center;">+43.1%</td><td style="text-align:center;">正向（但 OpEx 攀升侵蝕部分）</td></tr></tbody></table><h3 id="三、費用侵蝕臨界審查" tabindex="-1">三、費用侵蝕臨界審查 <a class="header-anchor" href="#三、費用侵蝕臨界審查" aria-label="Permalink to &quot;三、費用侵蝕臨界審查&quot;">​</a></h3><ul><li><strong>年度費用率優化</strong>：OpExp/Rev 從 2024 年 14.26% 降至 2025 年 14.02%（-24 bps），顯示費用控管並未失控。</li><li><strong>季度費用率波動</strong>：2025 Q4 OpExp/Rev 跳升至 18.83%，其中推銷費用 (Selling Expense) 佔營收比達 14.88%（較 2025 Q1 的 8.22% 增加 +666 bps），推銷費用年增 75.1% 快於營收年增 20.0%。 <ul><li><strong>風險標註</strong>：此為「季度行銷擴張」模式——配合年底新品出貨旺季投入行銷資源。雖未觸及「燒錢換營收」警戒線（因營收增幅仍達 20%），但需密切關注。</li></ul></li><li><strong>R&amp;D 投入</strong>：R&amp;D/Rev 僅 0.62%~1.08%，絕對值偏低，屬於製造業定型化產品的合理區間，無技術築牆或大幅轉型需求。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="一、三率結構判讀" tabindex="-1">一、三率結構判讀 <a class="header-anchor" href="#一、三率結構判讀" aria-label="Permalink to &quot;一、三率結構判讀&quot;">​</a></h3><p>良維的三率連動呈現「<strong>GM 帶動型</strong>」結構（非費用壓縮型 Growth）。GM +656 bps 的擴張才是 OPM +598 bps 改善的根本動力，顯示公司產品組合從低毛利的消費性電源線轉向高毛利的大電流 / 資料中心電源線，已產生<strong>結構性獲利升級</strong>。</p><h3 id="二、經營槓桿質量" tabindex="-1">二、經營槓桿質量 <a class="header-anchor" href="#二、經營槓桿質量" aria-label="Permalink to &quot;二、經營槓桿質量&quot;">​</a></h3><p>DOL 3.41x 表示良維已進入「固定成本槓桿」階段——隨著營收規模突破 100 億台幣，折舊、薪資等固定成本佔比在稀釋效應下逐步降低。2025 年 OpExp/Rev 僅 14.02% (低於 2024 年的 14.26%) 即為佐證。</p><ul><li><strong>固定資產槓桿</strong>：泰國廠產能利用率已達 70-80%，新增產能持續貢獻營收但折舊攤提相對固定，正向貢獻 DOL。</li><li><strong>潛在風險</strong>：若營收成長放緩至 10% 以下，DOL 的 3.41x 也意味著 OpInc 可能萎縮達 34%，需警惕需求反轉時的負向槓桿。</li></ul><h3 id="三、競爭情境分析-2008-年-vs-2025-年" tabindex="-1">三、競爭情境分析（2008 年 vs 2025 年） <a class="header-anchor" href="#三、競爭情境分析-2008-年-vs-2025-年" aria-label="Permalink to &quot;三、競爭情境分析（2008 年 vs 2025 年）&quot;">​</a></h3><p>良維所處的電源線產業具備<strong>安規證書護城河</strong>（全球 33 國認證，累積 50 年）。大電流領域主要競爭對手為台商及國際大廠（如安費諾），中國廠商因國安 / 資料安全問題難以切入資料中心供應鏈。這賦予良維<strong>結構性定價保護</strong>—即使銅價波動（從 6,000 USD/噸升至 11,000 USD/噸），大電流產品毛利率受影響極小。</p><h3 id="四、前景判斷" tabindex="-1">四、前景判斷 <a class="header-anchor" href="#四、前景判斷" aria-label="Permalink to &quot;四、前景判斷&quot;">​</a></h3><ul><li><strong>正向因素</strong>：2026 Q1 營收 26.1 億元，YoY +11.5%，維持兩位數成長動能；2025 年 EPS 8.31 元；泰國廠持續擴建；AI 資料中心資本支出 CAGR 30%+ 驅動需求。</li><li><strong>關注變數</strong>：2025 Q4 推銷費用暴增是否為常態化；EV 產品線因中國競爭持續萎縮；匯兌損失對單季 EPS 的擾動。</li><li><strong>綜合判定</strong>：良維處於「規模經濟收割期」，DOL 正向效益可望延續至 2026 年，但 Q4 行銷費用率偏高（18.83%）需監控是否成為趨勢。</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>FinMind 數據採集器</code>: python3 數據採集器.py finance 6290 2023-04-01 2026-04-24 --df (科目：營業收入、營業成本、營業毛利、營業費用、營業利益、稅前淨利、本期淨利、歸屬母公司淨利、EPS)</li><li><code>FinMind 數據採集器</code>: python3 數據採集器.py info 6290 (確認公司為上櫃電子零組件業，代號 6290.TWO)</li><li><code>yfinance 數據採集器</code>: python3 數據採集器.py yf_info 6290.TWO (獲取 EPS 8.31、毛利率 31.42%、營益率 16.32%、營收 10,158M)</li><li><code>yfinance 數據採集器</code>: python3 數據採集器.py yf_q_financials 6290.TWO (獲取推銷費用、管理費用、研發費用明細 breakdown)</li><li><code>FinMind 月營收</code>: python3 數據採集器.py revenue 6290 2023-01-01 2026-04-24 --df (逐月營收驗證季度彙總一致性)</li><li><code>Web Search (vocus)</code>: <a href="https://vocus.cc/article/67b93f6cfd89780001b3ae5a" target="_blank" rel="noreferrer">https://vocus.cc/article/67b93f6cfd89780001b3ae5a</a> (良維法說內容、產品組合佔比、銅價與毛利率關係)</li><li><code>Web Search (Threads/AlphaMemo)</code>: 良維 6290 法人 memo（資料中心營收佔比 36%、泰國廠利用率 70-80%、EV 產品線萎縮、配息率 78%）</li><li><code>Web Search (MoneyDJ)</code>: <a href="https://www.moneydj.com/kmdj/news/newsviewer.aspx" target="_blank" rel="noreferrer">https://www.moneydj.com/kmdj/news/newsviewer.aspx</a> (2025 年毛利率 31.42%，EPS 8.73 元)</li></ul><blockquote><p><strong>數據時效性宣告</strong>：以上數據截至 2026-04-24，涵蓋 2025 年報已公告之完整 2025 年度數據及 2026 Q1 月營收 (至 2026 年 3 月)。</p></blockquote>',34)])])}const h=e(r,[["render",d]]);export{y as __pageData,h as default};
